MAP
  NAME "nz-imagery"
  STATUS ON
  SIZE 256 256
  EXTENT 1722000 5900000 1812000 5970000
  UNITS METERS

  OUTPUTFORMAT
    NAME png24
    DRIVER "AGG/PNG"
    MIMETYPE "image/png"
    IMAGEMODE RGB
    EXTENSION "png"
  END

  OUTPUTFORMAT
    NAME jpeg
    DRIVER "AGG/JPEG"
    MIMETYPE "image/jpeg"
    IMAGEMODE RGB
    EXTENSION "jpg"
  END

  IMAGETYPE PNG24
  IMAGECOLOR 255 255 255

  PROJECTION
    "init=epsg:2193"
  END

  WEB
    METADATA
      "ows_title"           "Auckland 2024 Imagery"
      "ows_abstract"        "Auckland 2024 0.075m aerial imagery mosaic (17739 COGs)"
      "ows_onlineresource"  "http://mapserver-1286789374.us-west-2.elb.amazonaws.com/mapserv"
      "ows_srs"             "EPSG:2193 EPSG:4326 EPSG:3857"
      "ows_enable_request"  "*"
    END
  END

  CONFIG "MS_ERRORFILE" "stderr"
  CONFIG "AWS_NO_SIGN_REQUEST" "YES"
  CONFIG "VSI_CACHE" "TRUE"
  CONFIG "VSI_CACHE_SIZE" "67108864"
  CONFIG "GDAL_DISABLE_READDIR_ON_OPEN" "TRUE"
  CONFIG "CPL_VSIL_CURL_ALLOWED_EXTENSIONS" ".tiff,.tif"

  LAYER
    NAME "auckland-2024"
    TYPE RASTER
    STATUS ON
    DATA "/usr/src/mapfiles/mosaic.vrt"
    PROCESSING "BANDS=1,2,3"
    PROJECTION
      "init=epsg:2193"
    END
    METADATA
      "ows_title"    "Auckland 2024 0.075m"
      "ows_abstract" "Auckland 2024 high-resolution aerial imagery"
    END
  END

END
